class Solution {
    public boolean canIWin(int maxChoosableInteger, int desiredTotal) {
        if ((1 + maxChoosableInteger) * maxChoosableInteger / 2 < desiredTotal) return false;
        int[] memo = new int[1 << maxChoosableInteger];
        return canWin(desiredTotal, 0, maxChoosableInteger, memo);
    }

    private boolean canWin(int total, int state, int maxChoosableInteger, int[] memo) {
        if (memo[state] != 0) return memo[state] == 1;
        for (int i = 0; i < maxChoosableInteger; i++) {
            if ((state & (1 << i)) == 0 && (i + 1 >= total || !canWin(total - (i + 1), state | (1 << i), maxChoosableInteger, memo))) {
                memo[state] = 1;
                return true;
            }
        }
        memo[state] = -1;
        return false;
    }
}
